INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), '1cr', 17, 1, NULL, 'Ulrich Zwingli em 1Cr 17:1', 'Na leitura de Ulrich Zwingli, vemos a centralidade das Escrituras e da graça soberana. 1 Crônicas 17 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Ulrich Zwingli', 'commentary', '#800080', NOW()),
(gen_random_uuid(), '1cr', 18, 1, NULL, 'John Wesley em 1Cr 18:1', 'Segundo John Wesley, o chamado ao arrependimento, fé viva e missão ilumina o sentido deste texto. 1 Crônicas 18 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em adoração reverente. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'John Wesley', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), '1cr', 19, 1, NULL, 'Adam Clarke em 1Cr 19:1', 'Na leitura de Adam Clarke, vemos a exposição textual com aplicação pastoral objetiva. 1 Crônicas 19 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em amor fraternal. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Adam Clarke', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), '1cr', 20, 1, NULL, 'João Calvino em 1Cr 20:1', 'João Calvino interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em 1 Crônicas 20, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'João Calvino', 'commentary', '#800080', NOW()),
(gen_random_uuid(), '1cr', 21, 1, NULL, 'John Brown of Haddington em 1Cr 21:1', 'John Brown of Haddington destaca a piedade prática e a santificação do coração. Em 1 Crônicas 21, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'John Brown of Haddington', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '1cr', 22, 1, NULL, 'Albert Barnes em 1Cr 22:1', 'Albert Barnes interpreta este versículo a partir de a exposição textual com aplicação pastoral objetiva. Em 1 Crônicas 22, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo santidade prática. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Albert Barnes', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), '1cr', 23, 1, NULL, 'Martinho Lutero em 1Cr 23:1', 'Segundo Martinho Lutero, a centralidade das Escrituras e da graça soberana ilumina o sentido deste texto. 1 Crônicas 23 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em obediência da fé. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Martinho Lutero', 'commentary', '#800080', NOW()),
(gen_random_uuid(), '1cr', 24, 1, NULL, 'Thomas Boston em 1Cr 24:1', 'Na leitura de Thomas Boston, vemos a piedade prática e a santificação do coração. 1 Crônicas 24 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Thomas Boston', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '1cr', 25, 1, NULL, 'Herman Bavinck em 1Cr 25:1', 'Segundo Herman Bavinck, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. 1 Crônicas 25 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Herman Bavinck', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '1cr', 26, 1, NULL, 'Bernardo de Claraval em 1Cr 26:1', 'Bernardo de Claraval destaca a síntese entre fé, razão e vida santa. Em 1 Crônicas 26, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Bernardo de Claraval', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), '1cr', 27, 1, NULL, 'William Gurnall em 1Cr 27:1', 'William Gurnall interpreta este versículo a partir de a piedade prática e a santificação do coração. Em 1 Crônicas 27, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'William Gurnall', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '1cr', 28, 1, NULL, 'Louis Berkhof em 1Cr 28:1', 'Louis Berkhof destaca a coerência doutrinária aplicada à vida cristã. Em 1 Crônicas 28, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Louis Berkhof', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '1cr', 29, 1, NULL, 'Anselmo de Cantuária em 1Cr 29:1', 'Na leitura de Anselmo de Cantuária, vemos a síntese entre fé, razão e vida santa. 1 Crônicas 29 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Anselmo de Cantuária', 'commentary', '#6B4F2A', NOW()),
(gen_random_uuid(), '2cr', 1, 1, NULL, 'Charles Spurgeon em 2Cr 1:1', 'Na leitura de Charles Spurgeon, vemos a coerência doutrinária aplicada à vida cristã. 2 Crônicas 1 evidencia providência divina na história do povo de Deus como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Charles Spurgeon', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '2cr', 2, 1, NULL, 'Jerônimo em 2Cr 2:1', 'Jerônimo interpreta este versículo a partir de a leitura cristológica e eclesial da passagem. Em 2 Crônicas 2, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Jerônimo', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), '2cr', 3, 1, NULL, 'John Owen em 2Cr 3:1', 'John Owen destaca a piedade prática e a santificação do coração. Em 2 Crônicas 3, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'John Owen', 'commentary', '#2E8B57', NOW()),
